import { makeObservable, observable, action, computed } from "mobx";

const ActualState = Object.freeze({
    Loading: "load",
    Error: { value: "error", message: "Произошла неизвестная ошибка" },
    Init: "Init",
    Success: { value: "success", message: "Операция успешно выполнена" }
})

class SignInViewModel {
    actualState = new ActualState.Init
    signInState = new SignInState()

    constructor(){
        makeObservable(this, {
            actualState: observable,
            signInState: observable,
            updateSignInState: action
        })
    }

    updateSignInState(newState) {
        this.signInState = newState
    }
}

export default new SignInViewModel()
